import { useState, useEffect } from 'react';
import fire from "../fire"
import BarChart from "./BarChart"
import Barchart1 from './BarChart1';
const Search = () => {

    const [data, setData] = useState(null);
    const [keywords, setKeywords] = useState('');
    const [country, setCountry] = useState('US');
    const [url, setUrl] = useState('')
    const [showComponent, setShowComponent] = useState(false);
    const [isLoading, setIsLoading] = useState(false)

    useEffect(() => {
        const fetchData = () => {
            setIsLoading(true);
            fetch(url).then(res => {
                return res.json();
            })
                .then(data => {
                    setData(data);
                    setIsLoading(false)
                })
                .catch(error => {
                    console.log(error.message)
                })
        }

        fetchData();
        console.log(data)

    }, [url]);

    const handleKeywords = (event) => { setKeywords(event.target.value) }
    const handleCountry = (event) => { setCountry(event.target.value) }
    const handleLogout = () => { fire.auth().signOut() }
    const clickSearch = () => {
        var url = 'http://localhost:5000/api/chart?keywords=' + keywords + '&country=' + country;
        setUrl(url)
    }

    return (
        <div>
            <button onClick={handleLogout}>Logout</button>
            <label>
                Search:
            <input type="text" value={keywords} onChange={handleKeywords} />
            </label>
            <select value={country} onChange={handleCountry}>
                <option defaultValue value="US">United States</option>
                <option value="AU">Australia</option>
                <option value="GB">Great Britain</option>
                <option value="FR">France</option>
            </select>
            <button type="button" onClick={clickSearch}>
                Search
                </button>

            {isLoading && <div>Loading...</div>}
            {data && <Barchart1 data={data} />}

        </div>
    );
}

export default Search;
